const cellAt = (
  model: GridViewModel,
  x: number,
  y: number,
): GridCellView => {
  const cell = model.cells.find((entry) => entry.x === x && entry.y === y);

  if (cell === undefined) {
    throw new Error(`missing cell ${x},${y}`);
  }

  return cell;
};

