): FogMemory => {
  assertFogMatchesGrid(fog, grid);

  return {
    ownerId: fog.ownerId,
    width: fog.width,
    height: fog.height,
    tiles: fog.tiles.map((memory, index) => {
      if (visible.has(index)) {
        return {
          state: "visible",
          rememberedTile: cloneTile(getTileAtIndex(grid, index)),
        };
      }

      if (memory.state === "visible") {
        return {
          state: "remembered",
          rememberedTile:
            memory.rememberedTile === null
