  KEYMAP_BINDINGS.filter((binding) => binding.showInOverlay !== false).map(
    (binding) => ({
      id: binding.id,
      group: binding.helpGroup,
      action: binding.helpAction,
      keys: binding.keyLabel,
    }),
  );

export const keymapOverlayGroups = (): readonly KeymapBinding["helpGroup"][] => [
  "Movement",
  "Actions",
  "Panels",
  "Universal",
];

