      return ["turn"];
    case "hp":
    case "maxHp":
      return ["hp"];
    case "fullness":
      return ["fullness"];
    case "level":
    case "xp":
    case "attack":
    case "defense":
      return ["levelXp"];
    case "status":
    case "statuses":
      return ["statuses"];
    default:
      return [];
  }
};

