        defenderHpAfter: 3,
      },
    } as GameState["log"][number],
    {
      turn: state.run.turn + 1,
      type: "status_tick",
      data: {
        entityId: "player",
        status: "regen",
        hpDelta: 2,
      },
    } as GameState["log"][number],
  ],
});
