 59	export type InputDispatchDeps = {
 60	  readonly dispatchAction: (action: RunAction) => void;
 61	  readonly patchUi: (patch: Partial<UiSlice>) => void;
 62	  readonly appendInputFeedback: (
 63	    actionKind: InputFeedbackActionKind,
 64	    reason: string,
