 69	export const dispatchGameKey = (
 70	  snapshot: InputDispatchSnapshot,
 71	  deps: InputDispatchDeps,
 72	  keyPress: GameKeyPress,
 73	): InputDispatchResult => {
 74	  const context = inputFocusContext(snapshot.ui);
 75	  const binding = resolveKeyBinding(keyPress.key, context);
 76	
 77	  if (binding === null) {
 78	    return {
 79	      status: "ignored",
 80	      reason: `unbound key in ${context}`,
 81	      preventDefault: false,
 82	    };
 83	  }
 84	
 85	  const intent = binding.intent;
 86	
 87	  if (
 88	    snapshot.ui.inputLocked &&
 89	    intent.kind === "run_action"
 90	  ) {
 91	    return { status: "input_locked", preventDefault: true };
 92	  }
 93	
 94	  switch (intent.kind) {
 95	    case "run_action":
 96	      return dispatchRunAction(snapshot, deps, intent.action, keyPress);
 97	    case "set_context_mode":
 98	      deps.patchUi({
 99	        contextPanelMode:
100	          snapshot.ui.contextPanelMode === intent.mode ? "inspect" : intent.mode,
101	      });
102	      return {
103	        status: "handled",
104	        intent: intent.kind,
105	        preventDefault: true,
106	      };
107	    case "toggle_diary":
108	      deps.patchUi({
109	        diaryOpen: !snapshot.ui.diaryOpen,
110	        artifactOpen: false,
111	      });
112	      return {
113	        status: "handled",
114	        intent: intent.kind,
115	        preventDefault: true,
116	      };
117	    case "open_keymap":
118	      deps.patchUi({ keymapOpen: true });
119	      return {
120	        status: "handled",
121	        intent: intent.kind,
122	        preventDefault: true,
123	      };
124	    case "close_keymap":
125	      deps.patchUi({ keymapOpen: false });
126	      return {
127	        status: "handled",
128	        intent: intent.kind,
129	        preventDefault: true,
130	      };
131	    case "close_top":
132	      closeTop(snapshot, deps);
133	      return {
134	        status: "handled",
135	        intent: intent.kind,
136	        preventDefault: true,
137	      };
138	    case "confirm_yes":
139	      return confirmPending(snapshot, deps);
140	    case "confirm_no":
141	      cancelPendingConfirm(snapshot, deps);
142	      return {
143	        status: "handled",
144	        intent: intent.kind,
145	        preventDefault: true,
146	      };
147	  }
148	};
