150	export const inputFocusContext = (ui: UiSlice): KeyBindingContext => {
151	  if (ui.keymapOpen) {
152	    return "overlay";
153	  }
154	
155	  if (ui.diaryOpen || ui.artifactOpen) {
156	    return "paused-layer";
157	  }
158	
159	  if (ui.pendingConfirm !== null) {
160	    return "confirm";
161	  }
162	
163	  return "play";
164	};
