166	export const dangerousConfirmForAction = (
167	  state: GameState,
168	  action: RunAction,
169	): PendingConfirm | null => {
170	  if (action.kind !== "descend" || !isPlayerAction(action)) {
171	    return null;
172	  }
173	
174	  const legality = checkActionLegality(state, action);
175	  if (legality.status === "illegal") {
176	    return null;
177	  }
178	
179	  const adjacentEnemy = adjacentEnemies(state)[0];
180	  if (adjacentEnemy === undefined) {
181	    return null;
182	  }
183	
184	  return {
185	    action,
186	    prompt: `Enemy ${adjacentEnemy.id} is adjacent. Descend anyway? y/n`,
187	  };
188	};
189	
190	const dispatchRunAction = (
191	  snapshot: InputDispatchSnapshot,
192	  deps: InputDispatchDeps,
193	  action: RunAction,
194	  keyPress: GameKeyPress,
195	): InputDispatchResult => {
196	  if (snapshot.gameState === null) {
197	    return {
198	      status: "ignored",
199	      reason: "game state not ready",
200	      preventDefault: false,
201	    };
202	  }
203	
204	  if (keyPress.repeat === true && action.kind !== "move") {
205	    return {
206	      status: "ignored",
207	      reason: "non-move key repeat ignored",
208	      preventDefault: false,
209	    };
210	  }
211	
212	  if (keyPress.repeat === true && action.kind === "move") {
213	    const stop = autoTravelStopFor(snapshot.gameState);
214	    if (stop !== null) {
215	      deps.appendInputFeedback("move", stop.message);
216	      return {
217	        status: "travel_stopped",
218	        reason: stop.reason,
219	        preventDefault: true,
220	      };
221	    }
222	  }
223	
224	  const confirm = dangerousConfirmForAction(snapshot.gameState, action);
225	  if (confirm !== null) {
226	    deps.patchUi({ pendingConfirm: confirm });
227	    return {
228	      status: "confirm_required",
229	      confirm,
230	      preventDefault: true,
231	    };
232	  }
233	
234	  deps.dispatchAction(action);
235	  deps.lockInput();
236	
237	  return {
238	    status: "action_dispatched",
239	    action,
240	    preventDefault: true,
241	  };
242	};
243	
244	const confirmPending = (
245	  snapshot: InputDispatchSnapshot,
246	  deps: InputDispatchDeps,
247	): InputDispatchResult => {
248	  const pending = snapshot.ui.pendingConfirm;
249	  if (pending === null) {
250	    return {
251	      status: "ignored",
252	      reason: "no pending confirm",
253	      preventDefault: false,
254	    };
255	  }
256	
257	  deps.patchUi({ pendingConfirm: null });
258	  deps.dispatchAction(pending.action);
259	  deps.lockInput();
260	
261	  return {
262	    status: "action_dispatched",
263	    action: pending.action,
264	    preventDefault: true,
265	  };
266	};
267	
268	const closeTop = (
269	  snapshot: InputDispatchSnapshot,
270	  deps: InputDispatchDeps,
271	): void => {
272	  if (snapshot.ui.keymapOpen) {
273	    deps.patchUi({ keymapOpen: false });
274	    return;
275	  }
276	
277	  if (snapshot.ui.pendingConfirm !== null) {
278	    cancelPendingConfirm(snapshot, deps);
279	    return;
280	  }
281	
282	  if (snapshot.ui.diaryOpen || snapshot.ui.artifactOpen) {
283	    deps.patchUi({ diaryOpen: false, artifactOpen: false });
284	    return;
285	  }
286	
287	  if (snapshot.ui.contextPanelMode !== "inspect") {
288	    deps.patchUi({ contextPanelMode: "inspect" });
289	  }
290	};
291	
292	const cancelPendingConfirm = (
293	  snapshot: InputDispatchSnapshot,
294	  deps: InputDispatchDeps,
295	): void => {
296	  const pending = snapshot.ui.pendingConfirm;
297	  deps.patchUi({ pendingConfirm: null });
298	
299	  if (pending !== null && isInputFeedbackActionKind(pending.action.kind)) {
300	    deps.appendInputFeedback(pending.action.kind, "Cancelled.");
301	  }
302	};
303	
304	const adjacentEnemies = (state: GameState): readonly EntityInstance[] =>
305	  Object.values(state.entities)
306	    .filter((entity) => entity.kind === "enemy")
307	    .filter(
308	      (entity) =>
309	        chebyshevDistance(state.player.position, entity.position) <= 1,
310	    )
311	    .sort((left, right) => left.id.localeCompare(right.id));
312	
313	const isPlayerAction = (action: RunAction): action is PlayerAction =>
314	  action.kind !== "take_hoard";
315	
316	const isInputFeedbackActionKind = (
317	  kind: RunAction["kind"],
318	): kind is InputFeedbackActionKind => kind !== "take_hoard";

