 19	
 20	type RunEvent = Extract<RunLoopResult, { readonly ok: true }>["events"][number];
 21	
 22	export type ClientGameSessionStep = {
 23	  readonly state: GameState;
 24	  readonly events: readonly RunEvent[];
 25	};
 26	
 27	export type ClientGameSession = {
 28	  readonly state: GameState;
 29	  readonly step: (action: RunAction) => ClientGameSessionStep;
 30	  readonly replaceState: (state: GameState) => void;
 31	};
 32	
 33	export type ClientGameSessionOptions = {
 34	  readonly seed: string;
 35	  readonly provider?: FloorContentProvider;
 36	};
 37	
 38	export const createClientGameSession = ({
 39	  seed,
 40	  provider = createFallbackFloorContentProvider(),
 41	}: ClientGameSessionOptions): ClientGameSession => {
 42	  const started = startRun(seed, provider);
 43	  if (!started.ok) {
 44	    throw new Error(started.error.message);
 45	  }
 46	
 47	  let state = started.state;
 48	
 49	  return {
 50	    get state() {
 51	      return state;
 52	    },
 53	    step: (action) => {
 54	      const before = state;
 55	      const result = stepPlayerAction(before, action, provider);
 56	      if (!result.ok) {
 57	        throw new Error(result.error.message);
 58	      }
 59	
 60	      state = appendMissingReturnedEvents(before, result.state, result.events);
 61	
 62	      return {
 63	        state,
 64	        events: result.events,
 65	      };
 66	    },
 67	    replaceState: (nextState) => {
 68	      state = nextState;
 69	    },
 70	  };
 71	};
 72	
 73	const stepPlayerAction = (
 74	  state: GameState,
 75	  action: RunAction,
 76	  provider: FloorContentProvider,
 77	): RunLoopResult => {
 78	  const turnBefore = state.run.turn;
 79	  const result = stepRun(state, action, provider, {
 80	    hooks: dialogueTurnHooks(),
 81	  });
 82	
 83	  if (!result.ok) {
 84	    return result;
 85	  }
 86	
 87	  let nextState = result.state;
 88	  const events = [...result.events];
 89	
 90	  if (action.kind === "talk" || isWorldPaused(state) || isWorldPaused(nextState)) {
 91	    nextState = freezeTurnCount(nextState, turnBefore);
 92	  }
 93	
 94	  return {
 95	    ok: true,
 96	    state: nextState,
 97	    events,
 98	  };
 99	};
100	
101	const appendMissingReturnedEvents = (
102	  before: GameState,
103	  after: GameState,
104	  events: readonly RunEvent[],
105	): GameState => {
106	  const appendedCount = Math.max(0, after.log.length - before.log.length);
107	  if (appendedCount >= events.length) {
108	    return after;
109	  }
110	
111	  return {
112	    ...after,
113	    log: [...after.log, ...events.slice(appendedCount)],
114	  };
115	};

