 55	export const useGameStore = create<GameStore>((set, get) => ({
 56	  gameState: null,
 57	  gameSession: null,
 58	  ui: defaultUi,
 59	  startGameSession: ({ seed }) => {
 60	    const gameSession = createClientGameSession({ seed });
 61	    set({
 62	      gameSession,
 63	      gameState: gameSession.state,
 64	      ui: defaultUi,
 65	    });
 66	  },
 67	  setGameState: (gameState) =>
 68	    set((current) => {
 69	      current.gameSession?.replaceState(gameState);
 70	      return { gameState };
 71	  }),
 72	  dispatchAction: (action) => {
 73	    const session = get().gameSession;
 74	    if (session === null) {
 75	      return null;
 76	    }
 77	
 78	    const result = session.step(action);
 79	    set({ gameState: result.state });
 80	    return result;
 81	  },
 82	  appendInputFeedback: (actionKind, reason) =>
 83	    set((current) => {
 84	      if (current.gameState === null) {
