 86	      }
 87	
 88	      const event = {
 89	        turn: current.gameState.run.turn,
 90	        type: "action_illegal",
 91	        data: {
 92	          actionKind,
 93	          reason,
 94	        },
 95	      } as const satisfies GameState["log"][number];
 96	      const gameState = {
 97	        ...current.gameState,
 98	        log: [...current.gameState.log, event],
 99	      };
100	
101	      current.gameSession?.replaceState(gameState);
102	
103	      return { gameState };
104	    }),
105	  setInputLocked: (inputLocked) =>
106	    set((current) => ({
107	      ui: { ...current.ui, inputLocked },
108	    })),
109	  patchUi: (patch) =>
110	    set((current) => ({
111	      ui: { ...current.ui, ...patch },
112	    })),
113	}));

