 5	
 6	export type AutoTravelStopReason =
 7	  | "enemy_sighted"
 8	  | "item_underfoot"
 9	  | "hp_threshold";
10	
11	export type AutoTravelStop = {
12	  readonly reason: AutoTravelStopReason;
13	  readonly message: string;
14	};
15	
16	export const autoTravelStopFor = (state: GameState): AutoTravelStop | null => {
17	  const hpStop = hpThresholdStop(state);
18	  if (hpStop !== null) {
19	    return hpStop;
20	  }
21	
22	  if (itemUnderfoot(state)) {
23	    return {
24	      reason: "item_underfoot",
25	      message: "Auto-travel stopped: item underfoot.",
26	    };
27	  }
28	
29	  if (enemySighted(state)) {
30	    return {
31	      reason: "enemy_sighted",
32	      message: "Auto-travel stopped: enemy sighted.",
33	    };
34	  }
35	
36	  return null;
37	};
38	
39	export const hpStopPercentFor = (state: GameState): number =>
40	  config.difficultyGate.thresholdsByBand[state.run.band]
41	    .medianHpRetentionPercent.min;
42	
43	const hpThresholdStop = (state: GameState): AutoTravelStop | null => {
44	  const thresholdPercent = hpStopPercentFor(state);
45	  const currentPercent =
46	    state.player.hp.max <= 0
47	      ? 0
48	      : (state.player.hp.current / state.player.hp.max) * 100;
49	
50	  if (currentPercent > thresholdPercent) {
51	    return null;
52	  }
53	
54	  return {
55	    reason: "hp_threshold",
56	    message: `Auto-travel stopped: HP at ${Math.ceil(currentPercent)}%, threshold ${thresholdPercent}%.`,
57	  };
58	};
59	
60	const itemUnderfoot = (state: GameState): boolean =>
61	  Object.values(state.entities).some(
62	    (entity) =>
63	      entity.kind === "item" && samePosition(entity.position, state.player.position),
64	  );
65	
66	const enemySighted = (state: GameState): boolean =>
67	  Object.values(state.entities).some(
68	    (entity) => entity.kind === "enemy" && isVisible(state, entity.position),
69	  );
70	
71	const isVisible = (state: GameState, position: Position): boolean => {
72	  const grid = gridFromState(state);
73	  if (grid === null) {
74	    return false;
75	  }
76	
77	  const fog = fogFromState(state, grid) ?? defaultVisibleFog(grid);
78	  const index = idx(grid, position);
79	  if (index < 0 || index >= fog.tiles.length) {
80	    return false;
81	  }
82	
83	  return fogAt(fog, position).state === "visible";
84	};
85	
86	const samePosition = (left: Position, right: Position): boolean =>
87	  left.x === right.x && left.y === right.y;

